<template><el-card><template #header>规则库</template><PageToolbar><el-input v-model="q" placeholder="搜索规则"/><template #actions><el-button type="primary" @click="dialog=true">新建规则</el-button></template></PageToolbar><DataTable :data="filtered"><el-table-column prop="name" label="规则名称" min-width="200"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="region" label="适用区域"/><el-table-column prop="condition" label="条件摘要"/><el-table-column prop="conclusion" label="结论摘要"/><el-table-column prop="evidence" label="依据资产"/><el-table-column prop="priority" label="优先级"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column prop="version" label="版本"/><el-table-column label="操作" width="260"><template #default="s"><el-button link @click="edit=s.row;dialog=true">编辑</el-button><el-button link>查看依据</el-button><el-button link>测试规则</el-button><el-button link type="warning" @click="s.row.status='reviewing'">提交审核</el-button><el-button link type="success" @click="s.row.status='published'">发布</el-button></template></el-table-column></DataTable><el-dialog v-model="dialog" title="规则编辑" width="640"><el-form label-width="90"><el-form-item label="规则名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="条件"><el-input type="textarea" v-model="form.condition"/></el-form-item><el-form-item label="结论"><el-input type="textarea" v-model="form.conclusion"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { rules } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; import PageToolbar from '@/components/PageToolbar.vue'; import StatusTag from '@/components/StatusTag.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(rules))); const q=ref(''); const filtered=computed(()=>rows.value.filter(i=>!q.value||JSON.stringify(i).includes(q.value))); const dialog=ref(false); const edit=ref<any>(); const form=ref<any>({}); function save(){ if(edit.value) Object.assign(edit.value,form.value); else rows.value.unshift({id:Date.now(),name:form.value.name||'新建规则',domain:'通用',region:'全省',condition:form.value.condition||'',conclusion:form.value.conclusion||'',evidence:'待绑定',priority:50,status:'draft',version:'v0.1'}); dialog.value=false; form.value={}; edit.value=null}</script>
